import { Component, OnInit } from '@angular/core';
import { FirebaseDatabase } from '@angular/fire';
import { AngularFireDatabase } from '@angular/fire/database';
import { AngularFireAuth } from '@angular/fire/auth';
import { EmailListItem } from 'src/app/models/email-list-item';

@Component({
  selector: 'app-login',
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.scss']
})
export class LoginComponent implements OnInit {

  emailList: EmailListItem[] = [];
  uniqueEmails: Set<any> = new Set();
  emailByTopic = {};
  isLogged: boolean = false;

  userForm = {
    email: '',
    password: ''
  };

  user: firebase.User;
  

  constructor(
    private db: AngularFireDatabase,
    private auth: AngularFireAuth,
  ) {
   this.auth.authState.subscribe(user => {
     if(user) {
       this.user = user;
       this.fetchData();
       this.isLogged = true;
     }
   })
  }

  get topics() {
    return Object.keys(this.emailByTopic);
  }

  fetchData() {
    this.db.list<EmailListItem>('emails-ebook').valueChanges().subscribe(data => {
      this.emailList = data.map(el => {
        return <EmailListItem> {
          ebook: el.ebook,
          email: el.email,
          topic: el.topic ? el.topic : 'general',
          added: el.added
        };
      });
      this.uniqueEmails = new Set(this.emailList.map(emailItem => emailItem.email));
      let i = 0;
      this.emailList.forEach(e=> {
        let topic = e.topic;
        if(!this.emailByTopic[topic]) this.emailByTopic[topic] = [];
        if(!this.emailByTopic[topic].includes(e.email)) {
          this.emailByTopic[topic].push(e.email);
        }
      });
    });
  }

  doLogin() {
    this.auth.auth.signInWithEmailAndPassword(this.userForm.email, this.userForm.password)
    .then(userCredential => {
      this.user = userCredential.user;
    }).catch(err => {
      console.log(err)
      alert('Erro ao efetuar login');
    });
  }

  async doLogout() {
    await this.auth.auth.signOut();
    this.user = null;
    this.isLogged = false;
  }

  ngOnInit() {
  }

}
